import { useEffect, useState } from "react";
import { downloadReceiptPdf, getReceipts } from "../services/api";
import "../css/Receipts.css";

function Receipts() {
  const [receipts, setReceipts] = useState([]);

  const loadReceipts = async () => {
    try {
      const response = await getReceipts();
      setReceipts(response.data || []);
    } catch (error) {
      setReceipts([]);
    }
  };

  useEffect(() => {
    loadReceipts();
  }, []);

  const handleDownload = async (receipt) => {
    const response = await downloadReceiptPdf(receipt._id);
    const url = URL.createObjectURL(new Blob([response.data], { type: "application/pdf" }));
    const link = document.createElement("a");
    link.href = url;
    link.download = `receipt-${receipt.receiptNumber}.pdf`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleShareWhatsApp = (receipt) => {
    const text = `Receipt ${receipt.receiptNumber}
Invoice: ${receipt.invoiceId?.invoiceNumber || "N/A"}
Amount: Rs ${Number(receipt.totalAmount).toLocaleString("en-IN")}
Status: ${receipt.status}
Thank you for shopping with our Kirana Store.`;
    const waUrl = `https://wa.me/?text=${encodeURIComponent(text)}`;
    window.open(waUrl, "_blank");
  };

  return (
    <section className="receipts-page">
      <div className="container-fluid">
        <div className="receipts-header mb-4">
          <h2 className="receipts-title">Receipts</h2>
          <p className="receipts-subtitle">View and download approved payment receipts.</p>
        </div>

        <div className="card border-0 shadow-sm">
          <div className="card-body">
            <div className="table-responsive">
              <table className="table align-middle receipts-table">
                <thead>
                  <tr>
                    <th>Receipt No</th>
                    <th>Invoice No</th>
                    <th>Customer</th>
                    <th>Total</th>
                    <th>Status</th>
                    <th>Date</th>
                    <th>Download</th>
                    <th>Share</th>
                  </tr>
                </thead>
                <tbody>
                  {receipts.length ? (
                    receipts.map((receipt) => (
                      <tr key={receipt._id}>
                        <td>{receipt.receiptNumber}</td>
                        <td>{receipt.invoiceId?.invoiceNumber}</td>
                        <td>{receipt.customerId?.name}</td>
                        <td>Rs {Number(receipt.totalAmount).toLocaleString("en-IN")}</td>
                        <td>
                          <span className="status-approved">{receipt.status}</span>
                        </td>
                        <td>{new Date(receipt.createdAt).toLocaleDateString("en-IN")}</td>
                        <td>
                          <button
                            type="button"
                            className="btn btn-sm btn-primary"
                            onClick={() => handleDownload(receipt)}
                          >
                            PDF
                          </button>
                        </td>
                        <td>
                          <button
                            type="button"
                            className="btn btn-sm btn-outline-success"
                            onClick={() => handleShareWhatsApp(receipt)}
                          >
                            WhatsApp
                          </button>
                        </td>
                      </tr>
                    ))
                  ) : (
                    <tr>
                      <td colSpan="8" className="text-center py-4">
                        No receipts available.
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}

export default Receipts;
